// modules/tasks/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Handles task creation, retrieval, and management utilities.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'GET', path: '/tasks', auth: true },
    ],
    functions: ['getTasksForTeam'],
    types: ['Task', 'PaginationParams'],
  },

  sideEffects: [
    'reads from: tasks table',
    'reads from: teams table',
  ],

  invariants: [
    'Each task must belong to exactly one team',
    'A user can only see tasks for their assigned team',
  ],
});

// modules/tasks/lib/types.ts
import { User, Session } from '../auth/module.contract';

export interface Task {
  id: number;
  title: string;
  description: string;
  dueDate: Date;
  completed: boolean;
  teamId: number;
}

export interface PaginationParams {
  limit: number;
  offset: number;
}

// modules/tasks/lib/db.ts
import { query } from '../db';

export async function getTasksForTeam(teamId: number, paginationParams: PaginationParams): Promise<Task[]> {
  const { limit, offset } = paginationParams;
  const result = await query(`
    SELECT * FROM tasks WHERE team_id = $1 LIMIT $2 OFFSET $3
  `, [teamId, limit, offset]);
  return result.rows as Task[];
}

// modules/tasks/routes.ts
import { Router } from 'bun';
import { requireUser, getSession } from '../auth/lib/auth';
import { getTasksForTeam } from './lib/db';

const router = new Router();

router.get('/tasks', async (req) => {
  const user = await requireUser(req);
  const session = await getSession(req);

  if (!session) {
    return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401 });
  }

  const paginationParams = {
    limit: parseInt(req.query.get('limit') || '10', 10),
    offset: parseInt(req.query.get('offset') || '0', 10),
  };

  try {
    const tasks = await getTasksForTeam(session.teamId, paginationParams);
    return new Response(JSON.stringify(tasks), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: 'Internal Server Error' }), { status: 500 });
  }
});

export default router;

// modules/tasks/module.ts
import contract from './module.contract';
import routes from './routes';

const module = {
  contract,
  routes,
};

export default module;

