export async function getTasksForTeam(teamId: number, paginationParams: PaginationParams): Promise<Task[]> {
  const { limit, offset } = paginationParams;
  const result = await query(`
    SELECT * FROM tasks WHERE team_id = $1 LIMIT $2 OFFSET $3
  `, [teamId, limit, offset]);
  return result.rows as Task[];
}

// modules/tasks/lib/result.ts
import { Result, ok, err } from '../result';

export async function getTasksForTeam(teamId: number, paginationParams: PaginationParams): Promise<Result<Task[], Error>> {
  try {
    const tasks = await query(`
      SELECT * FROM tasks WHERE team_id = $1 LIMIT $2 OFFSET $3
    `, [teamId, limit, offset]);
    return ok(tasks.rows as Task[]);
  } catch (error) {
